module checksum_calculator (
    input [7:0] data_in,
    output reg [7:0] checksum_out
);
    integer i;
    reg [7:0] obf_sum;

    always @(*) begin
        obf_sum = 8'b0;
        for (i = 0; i < 8; i = i + 1) begin
            obf_sum = obf_sum + data_in[i];
        end
        checksum_out = obf_sum % 256;
    end
endmodule
